    {
      "input": {
        "action": "apply_namespace_event",
        "patterns": [
          "ns*"
        ],
        "initial_namespaces": [],
        "event": {
          "type": "ADDED",
          "metadata": {
            "name": "ns1"
          }
        }
      },
      "expected_output": "notified=yes\nnamespaces=ns1\n"
    },
    {
      "input": {
        "action": "apply_namespace_event",
        "patterns": [
          "ns*"
        ],
        "initial_namespaces": [],
        "event": {
          "type": "MODIFIED",
          "metadata": {
            "name": "ns1"
          }
        }
      },
      "expected_output": "notified=yes\nnamespaces=ns1\n"
    },
    {
      "input": {
        "action": "apply_namespace_event",
        "patterns": [
          "ns*"
        ],
        "initial_namespaces": [
          "ns1"
        ],
